    def convert(number, fromdigits, todigits):
        if str(number)[0] == "-":
            number = str(number)[1:]
            neg = 1
        else:
            neg = 0

        x = 0
        for digit in str(number):
            x = x * len(fromdigits) + fromdigits.index(digit)

        if x == 0:
            res = todigits[0]
        else:
            res = ""
            while x > 0:
                digit = x % len(todigits)
                res = todigits[digit] + res
                x = int(x / len(todigits))
            if neg:
                res = "-" + res
        return res


